import { useState } from "react";
import "./Borrow.css";

export default function LibraryApp() {
  const [searchTerm, setSearchTerm] = useState("");
  const [books] = useState([
    { id: 1, title: "The Great Gatsby" },
    { id: 2, title: "To Kill a Mockingbird" },
    { id: 3, title: "1984" },
    { id: 4, title: "Pride and Prejudice" }
  ]);
  const [borrowedBooks, setBorrowedBooks] = useState([]);

  const borrowBook = (book) => {
    if (!borrowedBooks.some((b) => b.id === book.id)) {
      setBorrowedBooks([...borrowedBooks, book]);
    }
  };

  const filteredBooks = books.filter((book) =>
    book.title.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="library-container">
      <h1 className="library-title">Library Management</h1>

      {/* Search Box */}
      <input
        className="library-input"
        placeholder="Search for a book..."
        value={searchTerm}
        onChange={(e) => setSearchTerm(e.target.value)}
      />

      <h2 className="library-subtitle">Available Books</h2>
      {filteredBooks.length === 0 ? (
        <p className="empty-message">No books found</p>
      ) : (
        <ul className="book-list">
          {filteredBooks.map((book) => (
            <li key={book.id} className="book-item">
              <strong>{book.title}</strong>
              <button className="borrow-button" onClick={() => borrowBook(book)}>
                Borrow
              </button>
            </li>
          ))}
        </ul>
      )}

      <h2 className="library-subtitle">Borrowed Books</h2>
      {borrowedBooks.length === 0 ? (
        <p className="empty-message">No books borrowed</p>
      ) : (
        <ul className="book-list">
          {borrowedBooks.map((book) => (
            <li key={book.id} className="book-item">
              <strong>{book.title}</strong>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}
